   462→    "\x01\x02\x03\x04\x05\x06\x07\x08\x0a"
   463→    "\x0b\x0c\x0d\x0e\x0f\x10\x11\x12\x13\x14"
   464→    "\x15\x16\x17\x18\x19\x1a\x1b\x1c\x1d\x1e\x1f\x7f"
   465→  };
