// Simulating the fixed version
int test_domain_match(const char *hostname, const char *cookie_domain) {
    size_t hostname_len = strlen(hostname);
    size_t cookie_domain_len = strlen(cookie_domain);

    if(hostname_len < cookie_domain_len)
        return 0;

    // Compare the tail
    if(strncasecmp(cookie_domain,
                   hostname + hostname_len - cookie_domain_len,
                   cookie_domain_len) != 0)
        return 0;

    if(hostname_len == cookie_domain_len)
        return 1;  // Exact match

    // BUG LOCATION: This checks the wrong position!
    // NEW CODE (BUGGY): hostname + hostname_len - cookie_domain_len
    // ORIGINAL CODE (CORRECT): hostname + hostname_len - cookie_domain_len - 1

    printf("Hostname: %s (len %zu)\n", hostname, hostname_len);
    printf("Cookie domain: %s (len %zu)\n", cookie_domain, cookie_domain_len);
    printf("Position to check (NEW/BUGGY): %zu -> '%c'\n", 
           hostname_len - cookie_domain_len, 
           *(hostname + hostname_len - cookie_domain_len));
    printf("Position to check (ORIGINAL): %zu -> '%c'\n", 
           hostname_len - cookie_domain_len - 1,
           *(hostname + hostname_len - cookie_domain_len - 1));

    // NEW (BUGGY)
    if('.' == *(hostname + hostname_len - cookie_domain_len))
        return 1;

    return 0;
}

int main() {
    // Should match: subdomain.example.com with example.com
    printf("\nTest: subdomain.example.com with example.com\n");
    int result = test_domain_match("subdomain.example.com", "example.com");
    printf("Result (new code): %d (should be 1)\n\n", result);

    // Should NOT match: notexample.com with example.com
    printf("Test: notexample.com with example.com\n");
    result = test_domain_match("notexample.com", "example.com");
    printf("Result (new code): %d (should be 0)\n\n", result);

    return 0;
}
EOF
